let str: string = ""

for (let i: number = 0; i < 9; i++) {
  for (let j: number = 0; j < 6; j++) {
    if ((i + j) % 3 == 0) {
      str = str + "H"
    } else if ((i + j) % 3 == 1) {
      str = str + "K"
    } else {
      str = str + "T"
    }
  }
  str = str + "\n" // quebra a linha
}

console.log(str)
